import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        long val;
        Node next;
        Node(long v) { val = v; }
    }

    private static long getMiddleElement(Node head) {
        Node slow = head, fast = head;
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
        }
        return slow.val;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            Node head = null, tail = null;
            for (int i = 0; i < N; ++i) {
                long x = Long.parseLong(st.nextToken());
                Node nd = new Node(x);
                if (head == null) head = tail = nd; else { tail.next = nd; tail = nd; }
            }
            sb.append(getMiddleElement(head)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def get_middle(head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
    return slow.val

class Node:
    __slots__ = ('val', 'next')
    def __init__(self, v):
        self.val = v
        self.next = None

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        head = tail = None
        for _ in range(N):
            v = int(next(it))
            node = Node(v)
            if head is None:
                head = tail = node
            else:
                tail.next = node
                tail = node
        out.append(str(get_middle(head)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

